/** biome-ignore-all lint/complexity/noExcessiveLinesPerFunction: multiple tests in one describe function */
import { describe, expect, test } from 'bun:test';
import {
        minWindow,
        minWindow1,
} from '../../../src/problems/solved/0076_minimum-window-substring.js';

describe('minWindow', () => {
        test('basic test 1', () => {
                expect(minWindow('ADOBECODEBANC', 'ABC')).toStrictEqual('BANC');
        });

        test('basic test 2', () => {
                expect(minWindow('a', 'a')).toStrictEqual('a');
        });

        test('basic test 3', () => {
                expect(minWindow('a', 'aa')).toStrictEqual('');
        });

        test('basic test 4', () => {
                expect(minWindow('ab', 'b')).toStrictEqual('b');
        });

        test('basic test 5', () => {
                expect(minWindow('ab', 'a')).toStrictEqual('a');
        });

        test('basic test 6', () => {
                expect(minWindow('aa', 'aa')).toStrictEqual('aa');
        });

        test('basic test 7', () => {
                expect(minWindow('zzzzzzaab', 'baa')).toStrictEqual('aab');
        });

        test('basic test 8', () => {
                expect(minWindow('bba', 'ab')).toStrictEqual('ba');
        });

        test('basic test 9', () => {
                expect(minWindow('acbbaca', 'aba')).toStrictEqual('baca');
        });

        test('custom test 1', () => {
                expect(minWindow('ABCBECODEBAN', 'ABC')).toStrictEqual('ABC');
        });

        test('custom test 2', () => {
                expect(minWindow('AYXCBECODEBANC', 'ABC')).toStrictEqual(
                        'BANC',
                );
        });

        test('custom test 3', () => {
                expect(minWindow('AXBC', 'ABC')).toStrictEqual('AXBC');
        });

        test('custom test 4', () => {
                expect(minWindow('AXBCZZZABC', 'ABC')).toStrictEqual('ABC');
        });

        test('custom test 5', () => {
                expect(minWindow('bacbcaca', 'ab')).toStrictEqual('ba');
        });

        test('custom test 6 - time limit test', () => {
                expect(
                        minWindow(
                                '',
                                'aAbBcCdDeEfFgGhHiIjJkKlLmMnNoOpPqQrRsStTuUvVwWxXyYzZ',
                        ),
                ).toStrictEqual(
                        'aAbBcCdDeEfFgGhHiIjJkKlLmMnNoOpPqQrRsStTuUvVwWxXyYzZ',
                );
        });
});

